var e=JSON.parse(`[{"id":"L13_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"누, 누구야……!","JPN":"だ、誰……！","ENG":"W-who's there...?!","TWN":"誰，是誰……！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L14_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"어, 어라? 아무도 없잖아? 분명 무슨 소리가 들렸는데……?","JPN":"あ、あれ？　誰もいない？　確かに声が聞こえたのに……？","ENG":"H-huh? No one's here. But I'm sure I heard something...","TWN":"嗯？沒人嗎？我明明有聽到聲音……？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그래, 오늘은 무슨 일로 불렀나? 부사장?","JPN":"今日はどういった用件かね？　副社長？","ENG":"Oh, you wanted to see me, Vice President?","TWN":"說吧，副總找我有什麼事？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"지난주 회의 때 이상한 보고가 하나 올라왔더군요.","JPN":"先週会議の際におかしな報告が一つあがっていました。","ENG":"Something odd was reported during last week's meeting.","TWN":"上週會議中有收到可疑的報告，"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님께서 확인해 주셔야 할 것 같습니다.","JPN":"社長にご確認いただきたいのですが。","ENG":"I think it's a matter you need to handle yourself, Boss.","TWN":"必須和老闆確認一下。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"음? 중요한 내용인가?","JPN":"うん？　重要な内容なのか？","ENG":"Mm? Is it important?","TWN":"嗯？是什麼重要的內容嗎？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"일단은 괴담에 가까운 내용이었습니다.","JPN":"とりあえず怪談に近い内容だと言っておきましょう。","ENG":"The content of the report was closer to a ghost story.","TWN":"是類似都市傳說的內容。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"괴담?!","JPN":"怪談！？","ENG":"A ghost story?!","TWN":"都市傳說？！"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"네. 늦은 밤에 일을 하다 보면 회사 건물 옥상에서 음악 소리가 들려온다고 합니다.","JPN":"はい。夜遅くまで残って仕事をしていると、会社の屋上から演奏する音が聞こえてくるそうです。","ENG":"Yes. People have been hearing music coming from the rooftop when they are working late.","TWN":"是，聽說晚上在公司加班時，會從屋頂傳來音樂聲。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"레나 양이 확인하러 갔을 때는 문을 열자마자 음악이 뚝 끊기고 옥상은 텅 비어 있었다더군요.","JPN":"レナさんが確認しに行った時は、ドアを開けると演奏が止まり、屋上には誰もいなかったそうです。","ENG":"Lena went to investigate, but as soon as she opened the door, the music stopped and the rooftop was seemingly empty.","TWN":"蕾娜去確認的時候，門一打開音樂就停了，屋頂上也空蕩蕩的。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"화단을 일일이 들춰 봤는데 아무 흔적도 못 찾았다고 합니다.","JPN":"花壇を片っ端から確認しても、なんの痕跡もなかったとのことです。","ENG":"She searched every corner of the garden but couldn't find any traces.","TWN":"她把花圃都翻遍了，但什麼也沒發現。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"……호러물 시즌이라기엔 아직 이르지 않나?","JPN":"……まだ怪談の季節ではないと思うが？","ENG":"...Isn't it a bit early for horror season?","TWN":"……應該還沒到七月半吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"사장님도 모르는 사람들에게는 충분히 괴담처럼 보일 수 있는 분입니다.","JPN":"お言葉ですが、社長も知らない人にとっては十分怪談の類に見えます。","ENG":"For people who don't know you, you can also be mistaken for a ghost story too, Boss.","TWN":"對某些不認識老闆的人而言，你長得也很七月半。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L34_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"경미한 침식 현상일 가능성도 배제할 수는 없지만……","JPN":"軽微な侵食現象である可能性も排除はできませんが……","ENG":"We cannot exclude the possibility that it could be a minor Counterside Effect...","TWN":"雖然也有可能是輕度侵蝕現象……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LEESOOYEON_COFFIN_NULL_NULL","text":{"KOREA":"멋대로 우리 회사 이름을 팔아 옥상을 정원으로 만든 녀석 소행이 아닐까 싶어서 말이죠.","JPN":"勝手にわが社の名前を使って屋上を庭園にした者の仕業ではないかと思いまして。","ENG":"But I'm guessing it is the doing of the one who sold our company name and made the rooftop into a garden.","TWN":"不過我想來想去，最有可能就是擅自冒用公司名義把屋頂變成花園的那個人吧？"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LEESOOYEON_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"크흠, 흠…….","JPN":"コホン、コホン……","ENG":"A-ahem! Hmm...","TWN":"咳咳……"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"알겠네. 일단은 밤이 되길 기다려 봄세.","JPN":"承知した。とりあえず夜になるまで待ってみよう。","ENG":"Very well. I'll wait until this evening to check it out.","TWN":"我知道了，總之就先等到天黑再說吧。"},"stage":{"bg":"OFFICE","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"역시 부사장 말대로 자네였군.","JPN":"副社長のいう通り、やはり君だったか。","ENG":"So it was you, just like Vice President guessed.","TWN":"副總猜的沒錯，果然是你。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"아, 당신 왔어?","JPN":"あら、ダーリン？","ENG":"Oh, you're here.","TWN":"喔，你來啦？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"여기까지 직접 온 걸 보니 회사에서 무슨 말이 나왔나 보네.","JPN":"ここまで直接来たってことは、社内で苦情が出たのね。","ENG":"Seeing how you came up here yourself, did word get out at the company?","TWN":"你會親自來這裡，就表示公司裡開始有什麼流言吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"사정을 모르는 직원들 사이에서 말이 나왔다더군.","JPN":"事情を知らない社員たちの間で噂になっている。","ENG":"Some rumors among the employees.","TWN":"是那些不知情的員工之間在傳。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"모습을 감춘 게 오히려 불안의 원인이 된 모양이야.","JPN":"姿が見えないのがむしろ不安を助長してしまったようだ。","ENG":"It seems that you've made them more anxious by hiding your presence.","TWN":"你這樣來無影去無蹤的，反而容易令人誤以為是靈異事件。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"아. 일하는데 방해가 되었으려나.","JPN":"あ、仕事の邪魔になったかしら。","ENG":"Oh. Did I bother them while they were working?","TWN":"哎呀，我打擾到他們工作了嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"나중에 관리국 명의로 선물이라도 싸들고 방문해야 할까?","JPN":"今度管理局名義で正式に、この会社に挨拶でもしに来たほうがいいのかしら？","ENG":"Should I come visit with some gifts in the Administration's name?","TWN":"還是我買個禮物，找一天以管理局的名義正式拜訪一下？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 기타는 언제부터 치기 시작한 건가?","JPN":"そのギターはいつ始めたんだ？","ENG":"When did you start playing the guitar?","TWN":"你什麼時候開始彈吉他的？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"글쎄? 현실세계로 귀환한 뒤부터?","JPN":"さあね？　現実世界に帰還したあとかしら。","ENG":"Let me see... Around the time I returned to the Normalside?","TWN":"這個嘛？從回到現實世界後開始的吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"뭐, 출신은 어쩔 수 없는지 나도 모르게 음색에 빠져들 때는 있었지만…….","JPN":"まぁ、血は争えないというか、気がつくと音色にうっとりしていることもあったけれど……","ENG":"Guess I can't fool where I'm from, because there are times when I get immersed in the melody without even knowing...","TWN":"不知道是不是因為我的出身，有時候我會沉浸在音樂裡……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"악기는 다루고 싶지 않았어. 그것들이 떠올라서.","JPN":"楽器を弾きたくはなかったわ。やつらのことを思い出すから。","ENG":"I didn't want to play instruments because they remind me of them.","TWN":"但我不想彈奏樂器，因為會想起她們。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"……엘리시움 말이군.","JPN":"……エリシウムか。","ENG":"...You're talking about Elysium.","TWN":"……你是說愛樂組織嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"맞아. 그 가증스러운 개자식들.","JPN":"そう。あの忌まわしいクソ野郎ども。","ENG":"Yeah. Those despicable assholes.","TWN":"沒錯，就是那些可恨的傢伙。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"하지만 역시, 음악에나 악기에나 죄가 없다는 생각이 들더라.","JPN":"でもやっぱり、音楽や楽器には罪がないと思っちゃうのよね。","ENG":"But still, I thought that maybe music and instruments have no sin after all.","TWN":"但我認為音樂或樂器本身是無罪的。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그것들이 다루는 방식이 역겹다고 해야 하려나?","JPN":"あいつらの扱い方が気色悪いだけというか？","ENG":"But more, what disgusts me is their way of handling them.","TWN":"是她們演奏的方式很令人厭惡吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"흐음…… 갑자기 생각이 바뀌진 않았을 것 같은데…….","JPN":"ふむ……急に考えが変わったとは思えないな……","ENG":"Hmm... I don't think you suddenly changed your mind...","TWN":"嗯嗯……你不像是會突然改變想法的人……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"혹시 방금 연주하던 곡이 그 계기인가?","JPN":"もしかして、今演奏していた曲がきっかけか？","ENG":"Was the song you were just playing the trigger?","TWN":"是剛才你彈的那首曲子讓你拿起吉他的嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"맞아. 참고로 아직 미완성이야.","JPN":"ええ。ちなみにまだ未完成よ。","ENG":"Yeah. But it's still a work in progress.","TWN":"沒錯，但這首曲子還沒完成。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"요즘은 틈만 나면 연습 중이거든.","JPN":"最近は暇を見つけては練習しているの。","ENG":"I practice whenever I have free time.","TWN":"最近只要有時間我就會練習。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"듣기 좋은 멜로디야. 마음이 편해지는군.","JPN":"聞き心地の良いメロディーだ。心が安らぐ。","ENG":"It's a good melody. Listening to it makes me feel at peace.","TWN":"旋律很好聽，有種安心感。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그렇지?","JPN":"そうでしょう？","ENG":"I know, right?","TWN":"對吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"발레리가 만들던 곡이야. 얼마나 대작을 만들 생각이었는지 매일 붙들고 있었지.","JPN":"ヴァレリーが作っていた曲よ。いったいどんな傑作を作るつもりだったのか、ずっと弾いていたわ。","ENG":"Valeriy wrote it. He would work on it every day as if he was writing his magnum opus.","TWN":"這是瓦萊里做的曲子，他每天都在彈，彷彿在創作一首曠世巨作一樣。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……역시 그 아이도 헌화보다는 이걸 더 마음에 들어할 것 같거든.","JPN":"……やっぱりあの子も献花よりはこっちの方が気に入ってくれるだろうと思って。","ENG":"...And I think he'll prefer this to my laying a wreath on his grave.","TWN":"……比起到他墳前獻花，他應該更喜歡自己做的曲子被聽到吧？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"동감일세. 누군가 기억해 준다는 건 행복한 일이지.","JPN":"そうだな。誰かの記憶に残るのは幸せなことだ。","ENG":"I agree. It's nice to know that someone remembers you.","TWN":"我同意，有人記得自己是一件很幸福的事。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그럼 원작자가 만족할 만큼 완성도를 기대해도 되겠나?","JPN":"では、原作者が満足するほどの完成度を期待しても良いのかな？","ENG":"Then, can I expect the finished song to be something that the original creator would be satisfied with?","TWN":"那我可以期待你會完成一首連原創者都滿意的曲子嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"글쎄, 열심히 해 봐야지?","JPN":"さあね、頑張ってみるわ。","ENG":"I dunno. I'll have to try.","TWN":"嗯，當然要努力試試囉！"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"나도 기왕 완성하기로 한 거, 애들한테 발레리보다 못하다는 말 듣긴 싫거든.","JPN":"私もせっかく完成させるって決めたからには、みんなからヴァレリーより下手だって言われなくはないからね。","ENG":"Now that I've decided to finish it, I don't want the others to say that I'm worse than Valeriy.","TWN":"既然已經決定要完成它，我可不想聽到有人說我做的曲子輸給瓦萊里。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이런, 괜한 소리로 승부욕을 자극한 거 아닌지 모르겠군.","JPN":"おっと、余計なことを言って負けず嫌いのスイッチを押してしまったんじゃないか心配だな。","ENG":"Oh, dear. Perhaps I nudged your competitiveness side to come out.","TWN":"哎呀，我不是要激起你的勝負慾。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_LONELY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"후훗. 괜한 걱정이야.","JPN":"ふふっ、余計な心配よ。","ENG":"Haha. No need to worry about that.","TWN":"呵呵，你多心了。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"아, 가기 전에 연주 좀 들어줄 수 있어?","JPN":"あ、戻る前に一度演奏を聞いてくれない？","ENG":"Oh, before you go, would you like to have a listen?","TWN":"對了，在你離開前要聽聽看嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"후반부를 완성하려면 아직 멀었지만, 느낌이 잘 이어졌는지 궁금해서.","JPN":"後半はまだまだ完成とはほど遠いけど、曲の雰囲気を壊さずに出来ているか気になって。","ENG":"The latter part of the song is far from finished, but I'd like your feedback on how it feels.","TWN":"還要一些時間才能完成後半部，但我想確認一下曲風有一致嗎？"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"연주회에 초대해 준다니 내 쪽에서 고마워할 일이지.","JPN":"演奏会に招待してもらえるなら、ありがたく聞かせてもらおう。","ENG":"Inviting me to a personal recital, I'm honored.","TWN":"竟然可以受邀參加演奏會，我當然是很樂意囉。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그럼. 특등석까지 마련해 뒀는걸.","JPN":"ええ、特等席まで用意しておいたわよ。","ENG":"Of course. I even prepared the best seat in the house for you.","TWN":"還幫你預備了VIP席呢。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"자, 내 옆에 앉아. 이 자리가 경치는 제일 좋거든.","JPN":"さあ、私の隣に座って。ここが一番景色の良いところなの。","ENG":"Come and sit next to me. This seat also happens to have the best view.","TWN":"來，坐我旁邊，這裡聽得最清楚。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"……다른 사람에게 들려주는 건 처음이니까, 실수해도 웃지 말고.","JPN":"……誰かに聞かせるのは初めてだから、失敗しても笑わないでよね。","ENG":"...It's my first time playing it in front of an audience, so don't laugh even if I make a mistake.","TWN":"……這次我第一次彈給別人聽，彈錯也不能笑我喔。"},"stage":{"bg":"GAUNTLET","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}}]`);export{e as default};